    "source": "# Air Quality - Parameter distribution (criteria pollutants)\nprint(\"Air Quality - Parameter Distribution:\")\ndisplay(\n    df_air_verify\n    .groupBy(\"parameter_name\")\n    .count()\n    .orderBy(col(\"count\").desc())\n)",
